      "id": "bronze-exam-b-009",
      "number": 25,
      "title": "参照比較",
      "type": "single",
      "selectCount": 1,
      "difficulty": "standard",
      "level": "bronze",
      "prompt": "実行結果として正しいものを選びなさい。",
      "codeBlocks": [
        {
          "title": "コード",
          "code": "public class Main {\n    public static void main(String[] args) {\n        String a = new String(\"x\");\n        String b = new String(\"x\");\n        System.out.println(a == b);\n    }\n}"
        }
      ],
      "options": [
        {
          "key": "A",
          "text": "false"
        },
        {
          "key": "B",
          "text": "true"
        },
        {
          "key": "C",
          "text": "コンパイルエラー"
        },
        {
          "key": "D",
          "text": "実行時例外"
        }
      ],
