          "code": "interface Printable {\n    void print();\n}\nclass Report implements Printable {\n    public void print() { System.out.print(\"R\"); }\n}\npublic class Main {\n    public static void main(String[] args) {\n        Printable p = new Report();\n        p.print();\n    }\n}"
